export type GetMediaJobsQueryParams = {
  type?: "voice" | "deck";
  dinoId?: string;
  status?: "queued" | "running" | "completed" | "failed";
  limit?: number;
};

export const getMediaJobsUrl = (params?: GetMediaJobsQueryParams) => {
  if (!params) {
    return "/api/media/jobs";
  }

  const query = new URLSearchParams();
  if (params.type) query.set("type", params.type);
  if (params.dinoId) query.set("dinoId", params.dinoId);
  if (params.status) query.set("status", params.status);
  if (params.limit && Number.isFinite(params.limit)) {
    query.set("limit", String(Math.trunc(params.limit)));
  }

  const queryString = query.toString();
  return `/api/media/jobs${queryString ? `?${queryString}` : ""}`;
};

